import json
import anthropic

client = anthropic.Anthropic()

PII_CLASSIFIER_PROMPT = '''You are a PII detection system.
Analyze the following text and identify all personally identifiable information (PII).
PII includes: names, emails, phone numbers, addresses, SSNs, dates of birth,
financial account numbers, health/medical information, biometric identifiers,
and combinations of attributes that together could identify a person
(quasi-identifiers: e.g., age + job title + city).

Return JSON only:
{
  "has_pii": true/false,
  "entities": [
    {"type": "<type>", "text": "<exact text>", "reason": "<why it is PII>"}
  ]
}
No other text.'''

def llm_pii_detect(text: str,
                   model: str = 'claude-haiku-4-5-20251001') -> dict:
    response = client.messages.create(
        model=model,
        max_tokens=500,
        system=PII_CLASSIFIER_PROMPT,
        messages=[{'role': 'user', 'content': text}],
    )
    try:
        return json.loads(response.content[0].text)
    except json.JSONDecodeError:
        return {'has_pii': False, 'entities': [], 'parse_error': True}

# Example where regex and NER would miss but LLM catches:
# 'Our patient is a 45-year-old female firefighter from Springfield
#  who was admitted on March 3rd with chest pain.'
# -> quasi-identifier combination that is likely re-identifying

from sklearn.metrics import precision_recall_fscore_support
import numpy as np

def evaluate_pii_detector(
    texts: list[str],
    gold_spans: list[list[PIISpan]],
    detector_fn,
) -> dict:
    all_gold, all_pred = [], []

    for text, gold in zip(texts, gold_spans):
        pred = detector_fn(text)
        gold_set = {(s.entity_type, s.start, s.end) for s in gold}
        pred_set = {(s.entity_type, s.start, s.end) for s in pred}

        for span_key in gold_set | pred_set:
            all_gold.append(1 if span_key in gold_set else 0)
            all_pred.append(1 if span_key in pred_set else 0)

    p, r, f1, _ = precision_recall_fscore_support(
        all_gold, all_pred, average='binary', zero_division=0
    )
    return {'precision': p, 'recall': r, 'f1': f1}
